import{_ as a,o as t,c as p,j as r,a as b,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"光之唯语","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/近战武器/6.可升级/光之唯语.md","filePath":"4.资源分区/7.物品与装备/2.武器/近战武器/6.可升级/光之唯语.md"}'),s={name:"4.资源分区/7.物品与装备/2.武器/近战武器/6.可升级/光之唯语.md"};function o(d,e,l,_,i,c){return t(),p("div",null,[...e[0]||(e[0]=[r("h1",{id:"光之唯语",tabindex:"-1"},[b("光之唯语 "),r("a",{class:"header-anchor",href:"#光之唯语","aria-label":'Permalink to "光之唯语"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：绯红庆典040")])])],-1),n('<h1 id="光之唯语-1" tabindex="-1">光之唯语 <a class="header-anchor" href="#光之唯语-1" aria-label="Permalink to &quot;光之唯语&quot;">​</a></h1><p>光之唯语<br> 魔幻本质<br> 描述：光之唯语是一把漆黑的铸铁短矛，被用于日常守卫的工作而制作。<br> 也许这把枪并非看起来这样普通。<br> 光之唯语为差价升级</p><p>C级：灵光于枪<br> C+1000<br> 描述：“我举起了这把矛。”<br> “矛尖产生了一层层白光...”<br> 现在使用者使用光之唯语时，一层层柔和而璀璨的光芒自矛尖迸发，如同花瓣展开。<br> 分类：短矛<br> 专业：短矛<br> 武器伤害：10L<br> 武器特性：【轻灵】，【高速1】，【投掷武器】，【能量武器】<br> 武器体积：3<br> 伤害类型：能量-光能</p><p>【如指流光】：光之唯语可以作为投掷武器使用，当光之唯语被投出进行攻击后，若投掷距离小于最大射程的一半，则其可以将其立即回收至你的手上，若投掷距离大于最大射程的一半，其会在下个你的攻击回合开始时自动回转至其手中，这是一个【回力】效果。</p><p>B级：唯一誓言<br> B+2000<br> 描述：“我见，流星划过夜空，我见，群星已然闪耀。”<br> “我誓，为守护而战。”<br> 现在轻挥短矛，矛尖便化作一道流光，划破空气，留下一串璀璨的星痕，烙印在敌人身上。<br> 若投掷，则化作一颗坠落的流星，带着破空之声呼啸而出，如同幽灵一般出现在敌人身前。<br> 分类：短矛<br> 专业：短矛<br> 武器伤害：17L<br> 武器特性：【轻灵】，【高速1】，【投掷武器】，【能量武器】，【幻灭】<br> 武器体积：3<br> 伤害类型：能量-光能</p><p>【如指流光】：光之唯语可以作为投掷武器使用，当光之唯语被投出进行攻击后，若投掷距离小于最大射程的一半，则其可以将其立即回收至你的手上，若投掷距离大于最大射程的一半，其会在下个你的攻击回合开始时自动回转至其手中，这是一个【回力】效果。</p><p>【群星咆哮】：<br> 当你使用光之唯语的攻击命中一个目标后，目标需以意志豁免对抗你的伤害出目，若失败，你会在对方身上留下一个具有点点星光亮起的星痕，当目标处于你的敏感范围内时，视作你拥有针对目标的【真实视觉】，持续一个场景。</p><p>你同时只能维持对一个目标的【真实视觉】，如果你同时命中了多个目标，由你选择其中一个施加【真实视觉】。</p><p>当你对新的目标施加【真实视觉】后，原本目标的【真实视觉】效果消失。</p><p>当你使用光之唯语进行投掷攻击时，其将在投掷过程中遁入虚空，直接出现在敌人面前，在近战攻击时则会撕裂周围的空间，这是一个C级时空来源的【传送攻击】效果。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',12)])])}const m=a(s,[["render",o]]);export{f as __pageData,m as default};
